sp_css.css:
/*
Tasker Classification Banner and Badge
Used with <div class="taskform-classification-banner taskform-classification-banner-{{c.data.f.classification}}"> looks like a button
Used with <div class="badge taskform-classification-banner-{{c.data.classification}}"> looks like a pill
2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
  Put into a style sheet
*/

.taskform-classification-banner {
    border-radius: 8px;
    border: 3px solid $classification-border-color;
    display: table-cell;
    margin-bottom: 15px;
    margin-right: 5px; //new
    padding: 5px 10px 5px 10px; //before padding: 5px;
  }

.taskform-classification-banner-Unclassified {
  background-color: $classification-unclassified-bg;
  color: $classification-unclassified-text;
}

.taskform-classification-banner-Official {
  background-color: $classification-official-bg; 
  color: $classification-official-text;
}

.taskform-classification-banner-Protected {
  /* 2.7.0 | 2021-08-07 | mmcc | STRY0104884 Badges do not pass 508/WCAG compliance */
  /* change color to a brown and add semicolon */
  /* background-color: #44835e */
  background-color: $classification-protected-bg;
  color: $classification-protected-text;
}

.taskform-classification-banner-Restricted {
  background-color: $classification-restricted-bg; 
  color: $classification-restricted-text;
}

.taskform-classification-banner-Secret {
  background-color: $classification-secret-bg;
  color: $classification-secret-text;
}

.taskform-classification-banner-Top.Secret {
  background-color: $classification-top-secret-bg;
  color: $classification-top-secret-text;
}
